            if any(k in window for k in ['copied','duplicat','appear','repe','seen','times']):
                copies = int(num)
                break
    if copies is None:
        # last resort: choose the smallest number between 2 and 500
        nums = [int(x) for x in re.findall(r'\d+', desc_l)]
        candidates = [x for x in nums if 2 <= x <= 500]
